"},{"conversion_notes":"The Python graph adjacency traversal is converted into a Jac traversal-style ability over an adjacency dictionary. It keeps an explicit frontier list, avoiding Python-only recursion patterns while preserving reachability behavior.","jac_code":"def reachable_count(graph: dict[str, list[str]], start: str) -> int {
    seen = {};
    stack = [start];
    count = 0;
    while len(stack) > 0 {
        node_name = stack.pop();
        if node_name not in seen {
            seen[node_name] = True;
            count = count + 1;
            for next_name in graph[node_name] {
                if next_name not in seen {
                    stack.append(next_name);
                }
            }
        }
    }
    return count;
}
","python_code":"def reachable_count(graph, start):
    seen = set()
    stack = [start]
    count = 0
    while stack:
        node_name = stack.pop()
        if node_name not in seen:
            seen.add(node_name)
            count += 1
            for next_name in graph[node_name]:
                if next_name not in seen:
                    stack.append(next_name)
    return count
"},{"conversion_notes":"The Python task object becomes a Jac node with declared state. The complete method is modeled as a node ability that mutates the node field and returns the new status.","jac_code":"node Task {
    has title: str;
    has done: bool = False;

    def complete() -> bool {
        self.done = True;
        return self.done;
    }

    def status() -> str {
        if self.done {
            return "done";
        }
        return "open";
    }
}
","python_code":"class Task:
    def __init__(self, title):
        self.title = title
        self.done = False

    def complete(self):
        self.done = True
        return self.done

    def status(self):
