"},{"conversion_notes":"The Python maximum search is converted to a Jac ability with typed list input. It avoids library calls and keeps the single-pass behavior explicit.","jac_code":"def max_value(nums: list[int]) -> int {
    best = nums[0];
    for n in nums {
        if n > best {
            best = n;
        }
    }
    return best;
}
