"},{"conversion_notes":"The Python tree traversal is rewritten as an explicit stack-based Jac ability. This is a traversal rewrite that avoids relying on Python generator behavior while preserving preorder output.","jac_code":"def preorder_values(tree: dict[str, list[str]], start: str) -> list[str] {
    order = [];
    stack = [start];
    while len(stack) > 0 {
        current = stack.pop();
        order.append(current);
        children = tree[current];
        idx = len(children) - 1;
        while idx >= 0 {
            stack.append(children[idx]);
            idx = idx - 1;
        }
    }
    return order;
}
","python_code":"def preorder_values(tree, start):
    order = []
    stack = [start]
    while stack:
        current = stack.pop()
        order.append(current)
        for child in reversed(tree[current]):
            stack.append(child)
    return order
"},{"conversion_notes":"The Python validation helper becomes a small typed Jac ability. The conversion uses not value for boolean negation and keeps the rules clear in guard clauses.","jac_code":"def valid_username(name: str) -> bool {
