"},{"conversion_notes":"The Python grouping utility is converted to a Jac ability using dictionaries and lists. The function-to-ability conversion adds type annotations while preserving the grouping behavior.","jac_code":"def group_by_first(words: list[str]) -> dict[str, list[str]] {
    groups = {};
    for word in words {
        key = word[0];
        if key not in groups {
            groups[key] = [];
        }
        groups[key].append(word);
    }
    return groups;
}
